import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";
  const primaryQuery = "Will there be no change in Fed interest rates after the April 2026 meeting?";
  const relatedQuery = "April 2026 Fed decision contracts";
  const targetQuery = "Fed interest rates no change after April 2026 meeting";

  const discoveryBatch = await callMcpSkillsParallel({
    label: "fed-april-2026-discovery",
    calls: [
      {
        key: "primaryEvent",
        toolId,
        toolName: "search_and_get_outcomes",
        args: {
          query: primaryQuery,
          category: "business",
          sortBy: "volume"
        }
      },
      {
        key: "relatedFamily",
        toolId,
        toolName: "search_markets",
        args: {
          query: relatedQuery,
          category: "business",
          status: "live",
          limit: 25
        }
      }
    ]
  });

  const primaryEventResult =
    discoveryBatch.results.find((entry) => entry.key === "primaryEvent" && entry.status === "fulfilled")?.value || null;
  const relatedFamilyResult =
    discoveryBatch.results.find((entry) => entry.key === "relatedFamily" && entry.status === "fulfilled")?.value || null;

  const primaryOutcomes = Array.isArray(primaryEventResult?.outcomes) ? primaryEventResult.outcomes : [];
  const relatedCandidatesRaw = Array.isArray(relatedFamilyResult?.results) ? relatedFamilyResult.results : [];

  const relatedCandidates = relatedCandidatesRaw.filter((item) => {
    const title = String(item?.title || "").toLowerCase();
    const slug = String(item?.slug || "").toLowerCase();
    const text = `${title} ${slug}`;
    return (
      text.includes("fed") &&
      text.includes("april") &&
      (text.includes("2026") || text.includes("2026-04") || text.includes("rate") || text.includes("decision"))
    );
  });

  const targetOutcomeCandidates = pickTopSemanticCandidates({
    target: targetQuery,
    candidates: primaryOutcomes,
    requiredTerms: ["fed", "april", "2026"],
    avoidTerms: ["primary", "district", "individual state", "election"],
    limit: 3
  });

  const targetOutcome = targetOutcomeCandidates[0] || null;

  const relatedMarketCandidates = pickTopSemanticCandidates({
    target: relatedQuery,
    candidates: relatedCandidates,
    requiredTerms: ["fed", "april", "2026"],
    avoidTerms: ["march", "may", "june", "july", "meeting minutes"],
    limit: 5
  });

  const selectedRelatedMarket = relatedMarketCandidates[0] || null;

  if (!targetOutcome || !targetOutcome.tokenId || !targetOutcome.conditionId) {
    return {
      primaryQuery,
      relatedQuery,
      missingData: ["Could not deterministically select the primary no-change outcome with tokenId and conditionId"],
      attemptedBranches: ["search_and_get_outcomes", "search_markets"],
      discoveryTelemetry: discoveryBatch.summary,
      primaryEventTitle: primaryEventResult?.eventTitle || null,
      primaryMatchConfidence: primaryEventResult?.matchConfidence || null,
      primaryOutcomeCount: primaryOutcomes.length,
      relatedCandidateCount: relatedCandidates.length
    };
  }

  const efficiencyResult = await callMcpSkill({
    toolId,
    toolName: "check_market_efficiency",
    args: {
      conditionId: targetOutcome.conditionId
    }
  });

  const targetQuoteResult = await callMcpSkill({
    toolId,
    toolName: "analyze_market_liquidity",
    args: {
      tokenId: targetOutcome.tokenId
    }
  });

  let relatedComparisonResult = null;
  if (selectedRelatedMarket && selectedRelatedMarket.conditionId) {
    relatedComparisonResult = await callMcpSkill({
      toolId,
      toolName: "compare_event_outcome_quotes",
      args: {
        eventQuery: relatedQuery,
        limit: 8
      }
    });
  }

  const matchedOutcomes = Array.isArray(relatedComparisonResult?.matchedOutcomes)
    ? relatedComparisonResult.matchedOutcomes
    : [];

  const bestRelatedMatch = matchedOutcomes.find((item) => {
    const name = String(item?.matchedName || "").toLowerCase();
    return (
      name.includes("no change") ||
      name.includes("hold") ||
      name.includes("unchanged") ||
      name.includes("no hike") ||
      name.includes("no cut")
    );
  }) || matchedOutcomes[0] || null;

  return {
    primaryQuery,
    relatedQuery,
    discoveryTelemetry: discoveryBatch.summary,
    primaryEvent: {
      eventTitle: primaryEventResult?.eventTitle || null,
      eventUrl: primaryEventResult?.eventUrl || null,
      matchConfidence: primaryEventResult?.matchConfidence || null,
      searchMethod: primaryEventResult?.searchMethod || null
    },
    selectedPrimaryOutcome: {
      name: targetOutcome.name || null,
      tokenId: targetOutcome.tokenId || null,
      conditionId: targetOutcome.conditionId || null,
      price: targetOutcome.price ?? null,
